import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:go_router/go_router.dart';
import '../../../core/di/providers.dart';

class ProfilePage extends ConsumerWidget { const ProfilePage({super.key}); @override Widget build(BuildContext context, WidgetRef ref) { final user = ref.watch(authProvider).value; return Scaffold(appBar: AppBar(title: const Text('الحساب والإعدادات')), body: ListView(padding: const EdgeInsets.all(20), children: [Card(child: ListTile(leading: const CircleAvatar(child: Icon(Icons.person)), title: Text(user?.displayName ?? ''), subtitle: Text(user?.email ?? ''))), const SizedBox(height: 12), ListTile(leading: const Icon(Icons.account_balance_wallet_outlined), title: const Text('المحفظة وسجل العمليات'), onTap: () => context.push('/wallet')), ListTile(leading: const Icon(Icons.history), title: const Text('سجل الألعاب'), onTap: () => context.push('/history')), ListTile(leading: const Icon(Icons.notifications_none), title: const Text('الإشعارات'), onTap: () => context.push('/notifications')), const Divider(), ListTile(leading: const Icon(Icons.help_outline), title: const Text('المساعدة'), onTap: () => context.push('/help')), ListTile(leading: const Icon(Icons.support_agent), title: const Text('تواصل مع الدعم'), onTap: () => context.push('/support')), if (user?.isAdmin == true) ListTile(leading: const Icon(Icons.admin_panel_settings_outlined), title: const Text('لوحة الإدارة'), onTap: () => context.push('/admin')), const Divider(), ListTile(leading: const Icon(Icons.logout), title: const Text('تسجيل الخروج'), onTap: () => ref.read(authProvider.notifier).logout())])); }
}
